/* adm-userbyrole-sql-oracle.xml - actionLoginCount */

SELECT COUNT(1)
 FROM TADMIN_MST_UR
WHERE URKEY = #{urkey}
  AND DELYN = 'N'
AND CLOSDATE < #{sysdate}

mapper.sql:
		/* adm-userbyrole-sql-oracle.xml - selectUrUnionUrGrByRole */
			SELECT TB3.ROKEY
              FROM TADMIN_MST_UR TB1
              INNER JOIN TADMIN_MST_URGR TB2
                  	  ON TB1.URGRKEY = TB2.URGRKEY
              INNER JOIN TADMIN_MST_URGRXROGT TB3
              	  	  ON TB1.URGRKEY = TB3.URGRKEY
               WHERE 1 = 1


						AND TB1.URKEY = #{urkey}


						AND TB1.URKEY = #{surkey}


               UNION 
               SELECT ROKEY
                FROM TADMIN_MST_URXROGT 
               WHERE 1=1


						AND URKEY = #{urkey}


						AND URKEY = #{surkey}
